/// <summary>
/// Chain of command for validateWrite to prevent UI editing of fully received lines.
/// </summary>
public boolean validateWrite()
{
    boolean ret = next validateWrite();


    if (ret && this.RecId != 0)
    {

        if (this.isFormDataSource())
        {
            // Check if the line is fully received
            if (this.RemainPurchPhysical == 0 && this.PurchQty > 0)
            {
                ret = checkFailed(strFmt("Purchase order %1, Line %2 is fully received and cannot be edited.", this.PurchId, this.LineNumber));
            }
        }
    }

    return ret;
}
